import { test, expect } from '@playwright/test';

test('Amazon SG - Search phone and sort by Price: Low to High', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "phone".
  const searchBox = page.getByRole('combobox', { name: /search/i });
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('phone');
  await page.getByRole('button', { name: /search/i }).click();

  // 3. Select "Price: Low to High" sort option.
  // Wait for sort dropdown to be visible
  const sortDropdown = page.locator('span.a-dropdown-container');
  await expect(sortDropdown).toBeVisible({ timeout: 15000 });

  // Open the sort dropdown
  await sortDropdown.click();

  // Select the "Price: Low to High" option
  const lowToHighOption = page.getByRole('option', { name: 'Price: Low to High' });
  await expect(lowToHighOption).toBeVisible({ timeout: 10000 });
  await lowToHighOption.click();

  // 4. Wait for results refresh.
  // Wait for the page to show the sorted results (wait for URL param or spinner)
  await expect(page).toHaveURL(/sort=price-asc-rank/, { timeout: 15000 });

  // 5. Validate sorting dropdown reflects selected option.
  // The selected option is visible in the dropdown button
  const selectedSort = page.locator('span.a-dropdown-prompt');
  await expect(selectedSort).toHaveText('Price: Low to High', { timeout: 10000 });

  // 6. Close browser.
  // (Playwright test runner handles browser close automatically)
});
